import os
import sys

import boto3
from botocore.exceptions import NoCredentialsError, PartialCredentialsError, ClientError

BUCKET_NAME = "demo-bucket"

# Provide credentials via environment variables or AWS config/SSO.
# Do NOT hardcode credentials in source code.
AWS_ACCESS_KEY_ID = os.getenv("AWS_ACCESS_KEY_ID")
AWS_SECRET_ACCESS_KEY = os.getenv("AWS_SECRET_ACCESS_KEY")
AWS_SESSION_TOKEN = os.getenv("AWS_SESSION_TOKEN")
AWS_REGION = os.getenv("AWS_REGION", "us-east-1")


def list_all_objects(s3_client, bucket: str):
    paginator = s3_client.get_paginator("list_objects_v2")
    found = False
    for page in paginator.paginate(Bucket=bucket):
        for obj in page.get("Contents", []):
            found = True
            print(obj["Key"])
    if not found:
        print("(bucket is empty or no access)")


def main():
    if not AWS_ACCESS_KEY_ID or not AWS_SECRET_ACCESS_KEY:
        print(
            "Missing AWS credentials.\n"
            "Set AWS_ACCESS_KEY_ID and AWS_SECRET_ACCESS_KEY (and optionally AWS_SESSION_TOKEN, AWS_REGION).\n"
            "Example (macOS/Linux):\n"
            "  export AWS_ACCESS_KEY_ID=...\n"
            "  export AWS_SECRET_ACCESS_KEY=...\n"
            "Example (Windows PowerShell):\n"
            "  $env:AWS_ACCESS_KEY_ID='...'\n"
            "  $env:AWS_SECRET_ACCESS_KEY='...'\n",
            file=sys.stderr,
        )
        sys.exit(2)

    try:
        s3 = boto3.client(
            "s3",
            region_name=AWS_REGION,
            aws_access_key_id=AWS_ACCESS_KEY_ID,
            aws_secret_access_key=AWS_SECRET_ACCESS_KEY,
            aws_session_token=AWS_SESSION_TOKEN,
        )
        list_all_objects(s3, BUCKET_NAME)
    except (NoCredentialsError, PartialCredentialsError) as e:
        print(f"Credential error: {e}", file=sys.stderr)
        sys.exit(2)
    except ClientError as e:
        print(f"AWS error: {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == "__main__":
    main()